SELECT id, product_id, buyer_id, seller_id, buyer_last_read_time, seller_last_read_time, create_time
FROM consult_session
WHERE id = #{id}

SELECT id, product_id, buyer_id, seller_id, buyer_last_read_time, seller_last_read_time, create_time
FROM consult_session
WHERE product_id = #{productId}
  AND buyer_id = #{buyerId}
LIMIT 1
